import { useState } from "react";
import axios from "axios";

export default function SubmitBug() {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [severity, setSeverity] = useState("Low");
  const [message, setMessage] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      const token = localStorage.getItem("token");

      await axios.post(
        "http://localhost:5000/api/bugs/submit",
        { title, description, severity },
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      );

      setMessage("✅ Bug submitted successfully");
      setTitle("");
      setDescription("");
      setSeverity("Low");
    } catch (err) {
      console.error(err);
      setMessage("❌ Failed to submit bug");
    }
  };

  return (
    <div className="min-h-screen flex justify-center items-center bg-gray-100">
      <form
        onSubmit={handleSubmit}
        className="bg-white p-6 rounded shadow w-[450px]"
      >
        <h2 className="text-xl font-bold mb-4">🐞 Submit Bug</h2>

        {message && <p className="mb-3">{message}</p>}

        <input
          className="w-full border p-2 mb-3 rounded"
          placeholder="Title"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          required
        />

        <textarea
          className="w-full border p-2 mb-3 rounded"
          placeholder="Description"
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          required
        />

        <select
          className="w-full border p-2 mb-4 rounded"
          value={severity}
          onChange={(e) => setSeverity(e.target.value)}
        >
          <option>Low</option>
          <option>Medium</option>
          <option>High</option>
          <option>Critical</option>
        </select>

        <button className="w-full bg-blue-600 text-white p-2 rounded">
          Submit Bug
        </button>
      </form>
    </div>
  );
}
